const items = $input.all();
const crypto = require('crypto');

// ── 1. Categorize sources ──
const competitors = items.filter(i => i.json.Type === 'competitor').map(c => ({ key: c.json.Key, url: c.json.URL, label: c.json.Label }));
const rssFeeds = items.filter(i => i.json.Type === 'rss_feed').map(r => ({ key: r.json.Key, url: r.json.URL, label: r.json.Label }));
const keywords = items.filter(i => i.json.Type === 'keyword').map(k => ({ key: k.json.Key, label: k.json.Label }));

// ── 2. Scrape competitors ──
const competitorResults = [];
for (const comp of competitors) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: comp.url,
      timeout: 10000,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; AnyVisionBot/1.0)' },
      returnFullResponse: true
    });
    const html = typeof response === 'string' ? response : (response.body || '');
    const newHash = crypto.createHash('sha256').update(html).digest('hex');
    const text = html
      .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .substring(0, 3000);
    competitorResults.push({ source: comp.label, url: comp.url, type: 'competitor', content: text, hash: newHash, hashKey: `content_hash_${comp.key}`, success: true });
  } catch(e) {
    competitorResults.push({ source: comp.label, url: comp.url, type: 'competitor', content: `Failed to scrape: ${e.message}`, hash: '', hashKey: `content_hash_${comp.key}`, success: false });
  }
  await new Promise(r => setTimeout(r, 2000));
}

// ── 3. Fetch RSS feeds ──
const rssResults = [];
for (const feed of rssFeeds) {
  try {
    const xml = await this.helpers.httpRequest({
      method: 'GET',
      url: feed.url,
      timeout: 10000,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; AnyVisionBot/1.0)' }
    });
    const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/gi;
    const titleRegex = /<title[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/i;
    const linkRegex = /<link[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/link>/i;
    const descRegex = /<description[^>]*>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/i;
    const dateRegex = /<pubDate[^>]*>(.*?)<\/pubDate>/i;
    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
    let match;
    let itemCount = 0;
    while ((match = itemRegex.exec(xml)) !== null && itemCount < 10) {
      const itemXml = match[1];
      const title = (titleRegex.exec(itemXml) || [])[1] || '';
      const link = (linkRegex.exec(itemXml) || [])[1] || '';
      const desc = (descRegex.exec(itemXml) || [])[1] || '';
      const dateStr = (dateRegex.exec(itemXml) || [])[1] || '';
      const pubDate = dateStr ? new Date(dateStr) : null;
      if (pubDate && pubDate < sevenDaysAgo) continue;
      const cleanDesc = desc.replace(/<[^>]+>/g, '').trim().substring(0, 500);
      rssResults.push({ source: feed.label, url: link, type: 'rss', title: title.trim(), content: cleanDesc, date: dateStr, success: true });
      itemCount++;
    }
  } catch(e) {
    rssResults.push({ source: feed.label, url: feed.url, type: 'rss', title: 'Failed to fetch', content: e.message, date: '', success: false });
  }
  await new Promise(r => setTimeout(r, 1000));
}

// ── 4. Build AI input ──
let aiInput = 'COMPETITOR INTELLIGENCE:\n';
for (const c of competitorResults) {
  if (c.success) aiInput += `\n--- ${c.source} (${c.url}) ---\n${c.content}\n`;
}
aiInput += '\n\nRSS FEED ARTICLES (Last 7 Days):\n';
for (const r of rssResults) {
  if (r.success) aiInput += `\n- [${r.source}] ${r.title}: ${r.content}\n`;
}
aiInput += '\n\nTARGET KEYWORDS: ' + keywords.map(k => k.label).join(', ');

return {
  json: {
    competitors: competitorResults,
    rssArticles: rssResults,
    keywords: keywords,
    totalSources: competitorResults.length + rssResults.length,
    aiInput: aiInput.substring(0, 8000),
    hashUpdates: competitorResults.filter(c => c.success).map(c => ({ key: c.hashKey, hash: c.hash }))
  }
};

