  };
}

// Calculate quality score (1-10)
let score = 5; // baseline
const fullText = `${parsed.hook} ${parsed.body} ${parsed.cta}`;
if (parsed.hook && parsed.hook.length > 10) score += 1;
if (parsed.body && parsed.body.length > 50) score += 1;
if (parsed.cta && parsed.cta.length > 10) score += 1;
if (parsed.hashtags && parsed.hashtags.split('#').length > 2) score += 1;
if (fullText.length > 100 && fullText.length < 1000) score += 1;

return {
  json: {
    parsedContent: parsed,
    qualityScore: score,
    calendarId: calendarItem.id,
    topic: calendarItem.Topic,
