  const hasError = !!(item.json.error || item.json.statusCode >= 400);
  return {
    json: {
      'Log ID': `LOG-${Date.now()}-${platform}`,
      'Content ID': formatData.contentID_field || formatData.contentId || '',
      'Platform': platform,
      'Published At': now,
      'Status': hasError ? 'Failed' : 'Success',
      'Response': JSON.stringify(item.json).substring(0, 200),
      _queueId: formatData.queueId || '',
      _contentId: formatData.contentId || '',
      _successCount: successCount,
      _failCount: failCount
    }
  };
});
return logEntries;

// Take only the first item to prevent 9x loop-back from parallel platform posts.
// All 9 distribution log entries are already stored — we just need one item
// to carry _queueId/_contentId/_successCount/_failCount forward.
return [$input.first()];

const now = new Date().toLocaleString('en-ZA', { timeZone: 'Africa/Johannesburg' });
let totalPublished = 0;
let totalFailed = 0;

try {
  const items = $('Process Results').all();
  if (items.length > 0) {
    // All items now have the same final totals, so read from first item
    totalPublished = items[0].json._successCount || 0;
    totalFailed = items[0].json._failCount || 0;
  }
} catch(e) {
  // No process results — queue was empty
}

return {
  json: {
    subject: `Marketing Distribution: ${totalPublished} posts published`,
    body: [
      '<h2>Daily Distribution Report</h2>',
      `<p><strong>Date:</strong> ${now}</p>`,
      '<hr>',
      `<p><strong>Successful Posts:</strong> ${totalPublished}</p>`,
      `<p><strong>Failed Posts:</strong> ${totalFailed}</p>`,
      '<hr>',
      '<p>Check your Airtable Distribution Log for per-platform details.</p>',
    ].join('\n')
  }
};
